def parse(self, content: str) -> List[Dict]:
    entries = []
    for line in content.strip().split('\n'):
        if not line.strip():
            continue
        try:
            parts = line.split(' ', 3)
            if len(parts) < 3:
                continue
            timestamp = datetime.strptime(
                f'{parts[0]} {parts[1]}', self.FORMAT
            )
            level = parts[2].strip('[]')
            message = parts[3] if len(parts) > 3 else ''
            entries.append({
                'timestamp': timestamp,
                'level': level,
                'message': message,
            })
        except (ValueError, IndexError):
            continue
    return entries
